import { Routes, Route } from 'react-router-dom';
import { HelmetProvider, Helmet } from 'react-helmet-async';
import Header from './components/layout/Header';
import Hero from './components/hero/Hero';
import LeadForm from './components/form/LeadForm';
import Benefits from './components/sections/Benefits';
import Features from './components/sections/Features';
import Pricing from './components/sections/Pricing';
import Steps from './components/sections/Steps';
import FAQ from './components/sections/FAQ';
import FinalCTA from './components/sections/FinalCTA';
import Footer from './components/layout/Footer';
import MentionsLegales from './pages/MentionsLegales';
import PolitiqueConfidentialite from './pages/PolitiqueConfidentialite';

function HomePage() {
  return (
    <>
      <Helmet>
        <title>Assurance Décennale Électricien | Devis Gratuit & Comparatif</title>
        <meta name="description" content="Obtenez votre assurance décennale pour electrician au meilleur prix. Devis gratuit et comparatif. RC Pro incluse. Réponse sous 24h. Obligatoire selon la loi Spinetta." />
        <meta name="keywords" content="assurance décennale, electrician, devis assurance, RC Pro, loi Spinetta, garantie décennale, assurance professionnel" />
        <meta name="robots" content="index, follow" />
        <meta property="og:title" content="Assurance Décennale Électricien | Devis Gratuit" />
        <meta property="og:description" content="Comparez les meilleures offres d'assurance décennale pour electricien. Devis gratuit en 2 minutes. RC Pro incluse." />
        <meta property="og:type" content="website" />
        <link rel="canonical" href="https://decennale-pro.fr/" />
      </Helmet>
      <Hero />
      <LeadForm />
      <Benefits />
      <Features />
      <Pricing />
      <Steps />
      <FAQ />
      <FinalCTA />
    </>
  );
}

export default function App() {
  return (
    <HelmetProvider>
      <div className="min-h-screen">
        <Header />
        <main>
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/mentions-legales" element={<MentionsLegales />} />
            <Route path="/politique-confidentialite" element={<PolitiqueConfidentialite />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HelmetProvider>
  );
}
